1	// R11.2 — Lull-interjection scheduled task.
2	//
3	// Per spec Part 5.1 Rule 2 + docs/oracle/05-ai-retrofit-phase-packet.md
4	// "Phase R11" + HANDOFF.md R11.2.
5	//
6	// Every minute, for each active channel:
7	//   1. Compute the inputs to decideLullInterjection (R11.1, pure):
8	//        - secondsSinceLastUserMessage
9	//        - minutesSinceLastOracleInterjection
10	//        - interjectionsInLastHour
11	//        - top relevant open gap for any channel participant
12	//   2. Call decideLullInterjection.
13	//   3. If decision = 'ask':
14	//        - Draft a natural question via OracleAIClient.runText on the
15	//          INTERVIEW route (Anthropic Claude Haiku 4.5) so the wording is
16	//          warm and chat-shaped, not extraction-style.
17	//        - Insert assistant message into `messages`.
18	//        - Insert `oracle_interventions` row with was_live_interjection=true,
19	//          interjection_message_id = the new assistant message id.
20	//        - Update gap: status='asked', askedInMessageId = the new message.
21	//
22	// Per HANDOFF.md the live-message-posting decision is intentional — no
23	// dry-run gating. Admin reviews via /admin/ai and oracle_interventions.
24	//
25	// Presence check (isAnyoneTyping): round 1 defaults to false. Wiring real
26	// Supabase Realtime presence is round 2.
27	//
28	// Topical relevance of the chosen gap: round 1 picks highest-priority open
29	// gap whose targetEmployeeId is null or is a channel participant. Embedding-
30	// based topical relevance vs recent message embeddings is round 2.
31	
32	import { schedules } from '@trigger.dev/sdk/v3';
33	import { and, desc, eq, gte, inArray, isNull, sql } from 'drizzle-orm';
34	import { createHash } from 'node:crypto';
35	import { getDirectDb } from '@oracle/db/client';
36	import {
37	  channelParticipants,
38	  channels,
39	  gaps,
40	  jobRuns,
41	  messages,
42	  modelRuns,
43	  modelRunUsageDetails,
44	  oracleContextPacks,
45	  oracleInterventions,
46	  settings,
47	  typingIndicators,
48	} from '@oracle/db/schema';
49	import {
50	  OracleAIClient,
51	  buildStandardAdapters,
52	  getOracleRoute,
53	  resolveRouteFromSettings,
54	  makeBlock,
55	  type OracleModelRoute,
56	} from '@oracle/ai';
57	import {
58	  decideLullInterjection,
59	  type LullInterjectionInput,
60	  type RelevantOpenGap,
61	} from '@oracle/engines';
62	
63	const FALLBACK_INTERVIEW_ROUTE_ID = 'anthropic_claude_haiku_4_5_interview_primary';
64	const LULL_INTERJECTION_PROMPT_VERSION = 'lull-interjection-1.0.0';
65	
66	// Recent user messages to thread into the drafting prompt for tone/topical context.
67	const RECENT_MESSAGE_CONTEXT_COUNT = 5;
68	
69	// Default setting values if the row is missing — match the seed in packages/db/src/seed.ts.
70	const DEFAULT_LULL_WINDOW_SECONDS = 60;
71	const DEFAULT_ORACLE_COOLDOWN_MINUTES = 10;
72	const DEFAULT_MAX_ORACLE_INTERJECTIONS_PER_HOUR = 3;
73	const DEFAULT_ENABLE_GROUP_CHAT_LULL_QUESTIONS = true;
74	
75	const LULL_DRAFT_SYSTEM = `You are the Oracle — an evidence-backed knowledge assistant for POP Creations / Spruce Line.
76	
77	The conversation in this chat has gone quiet. There's an open question the team should answer, and the recent discussion is on a topic where that answer would help.
78	
79	Your task: rephrase the open question as a warm, natural one-liner fit for chat. Match the tone of the recent messages. Do not introduce yourself, do not preamble, do not use markdown headings, do not say "I" or "the Oracle". Just ask the question.
80	
81	Hard rules:
82	- Return ONLY the question text — no preface, no explanation, no metadata.
83	- 200 characters or less.
84	- One question only.
85	- Plain text, no markdown.
86	- No fabricated specifics. If the open question already has a specific entity (Disney, Coldlion, etc.) keep it; otherwise stay generic.`;
87	
88	// ─── Module-singleton OracleAIClient (same pattern as the other workers) ────
89	function buildOracleClient(): OracleAIClient {
90	  return new OracleAIClient({
91	    adapters: buildStandardAdapters(),
92	    fallbackOnError: true,
93	  });
94	}
95	
96	function hashString(s: string): string {
97	  return createHash('sha256').update(s).digest('hex');
98	}
99	
100	// ─── Curated route resolver — INTERVIEW route (human-facing drafting) ───────
101	async function resolveInterviewRoute(
102	  db: ReturnType<typeof getDirectDb>,
103	): Promise<OracleModelRoute> {
104	  const resolved = await resolveRouteFromSettings(db, 'interview');
105	  if (resolved) return resolved;
106	  const fallback = getOracleRoute(FALLBACK_INTERVIEW_ROUTE_ID);
107	  if (!fallback) {
108	    throw new Error(
109	      `[lull-interjection] default_interview_route unset/unresolvable, and fallback "${FALLBACK_INTERVIEW_ROUTE_ID}" also missing.`,
110	    );
111	  }
112	  console.warn(
113	    `[lull-interjection] default_interview_route unset/unresolvable; using fallback "${FALLBACK_INTERVIEW_ROUTE_ID}".`,
114	  );
115	  return fallback;
116	}
117	
118	// ─── Settings loader ────────────────────────────────────────────────────────
119	interface LullSettings {
120	  lullWindowSeconds: number;
121	  oracleCooldownMinutes: number;
122	  maxOracleInterjectionsPerHour: number;
123	  enableGroupChatLullQuestions: boolean;
124	}
125	
126	async function loadLullSettings(
127	  db: ReturnType<typeof getDirectDb>,
128	): Promise<LullSettings> {
129	  const rows = await db
130	    .select({ key: settings.key, value: settings.value })
131	    .from(settings)
132	    .where(
133	      inArray(settings.key, [
134	        'lull_window_seconds',
135	        'oracle_cooldown_minutes',
136	        'max_oracle_interjections_per_hour',
137	        'enable_group_chat_lull_questions',
138	      ]),
139	    );
140	  const map = new Map(rows.map((r) => [r.key, r.value]));
141	  const num = (k: string, fallback: number) => {
142	    const v = map.get(k);
143	    return typeof v === 'number' ? v : fallback;
144	  };
145	  const bool = (k: string, fallback: boolean) => {
146	    const v = map.get(k);
147	    return typeof v === 'boolean' ? v : fallback;
148	  };
149	  return {
150	    lullWindowSeconds: num('lull_window_seconds', DEFAULT_LULL_WINDOW_SECONDS),
151	    oracleCooldownMinutes: num(
152	      'oracle_cooldown_minutes',
153	      DEFAULT_ORACLE_COOLDOWN_MINUTES,
154	    ),
155	    maxOracleInterjectionsPerHour: num(
156	      'max_oracle_interjections_per_hour',
157	      DEFAULT_MAX_ORACLE_INTERJECTIONS_PER_HOUR,
158	    ),
159	    enableGroupChatLullQuestions: bool(
160	      'enable_group_chat_lull_questions',
161	      DEFAULT_ENABLE_GROUP_CHAT_LULL_QUESTIONS,
162	    ),
163	  };
164	}
165	
166	// ─── Per-channel data fetch ─────────────────────────────────────────────────
167	interface ChannelContext {
168	  channelId: string;
169	  isGroupChat: boolean;
170	  secondsSinceLastUserMessage: number | null; // null = no user messages ever
171	  minutesSinceLastOracleInterjection: number | null;
172	  interjectionsInLastHour: number;
173	  topRelevantOpenGap: RelevantOpenGap | null;
174	  recentMessageExcerpts: string[];
175	  isAnyoneTyping: boolean;
176	}
177	
178	async function loadChannelContext(
179	  db: ReturnType<typeof getDirectDb>,
180	  channelId: string,
181	  isGroupChat: boolean,
182	  now: Date,
183	): Promise<ChannelContext> {
184	  // Last user message
185	  const lastUserMsgRows = await db
186	    .select({ createdAt: messages.createdAt, content: messages.content })
187	    .from(messages)
188	    .where(and(eq(messages.channelId, channelId), eq(messages.role, 'user'), isNull(messages.deletedAt)))
189	    .orderBy(desc(messages.createdAt))
190	    .limit(RECENT_MESSAGE_CONTEXT_COUNT);
191	
192	  const secondsSinceLastUserMessage =
193	    lastUserMsgRows.length > 0 && lastUserMsgRows[0]
194	      ? Math.floor((now.getTime() - lastUserMsgRows[0].createdAt.getTime()) / 1000)
195	      : null;
196	  const recentMessageExcerpts = lastUserMsgRows
197	    .slice()
198	    .reverse() // oldest-first for prompt readability
199	    .map((m) => m.content.slice(0, 240));
200	
201	  // Last oracle intervention in this channel
202	  const lastInterventionRows = await db
203	    .select({ createdAt: oracleInterventions.createdAt })
204	    .from(oracleInterventions)
205	    .where(eq(oracleInterventions.channelId, channelId))
206	    .orderBy(desc(oracleInterventions.createdAt))
207	    .limit(1);
208	  const minutesSinceLastOracleInterjection =
209	    lastInterventionRows.length > 0 && lastInterventionRows[0]
210	      ? Math.floor((now.getTime() - lastInterventionRows[0].createdAt.getTime()) / 60_000)
211	      : null;
212	
213	  // Interventions in last hour
214	  const oneHourAgo = new Date(now.getTime() - 60 * 60 * 1000);
215	  const countRows = await db
216	    .select({ c: sql<number>`count(*)::int` })
217	    .from(oracleInterventions)
218	    .where(
219	      and(
220	        eq(oracleInterventions.channelId, channelId),
221	        gte(oracleInterventions.createdAt, oneHourAgo),
222	      ),
223	    );
224	  const interjectionsInLastHour = countRows[0]?.c ?? 0;
225	
226	  // Top relevant open gap. Round 1: prioritize urgent > high > medium > low,
227	  // then prefer gaps whose targetEmployeeId is a channel participant (more
228	  // likely to land on someone present), then prefer most-recently-created.
229	  // No embedding-based topical relevance yet.
230	  const participantIds = await db
231	    .select({ id: channelParticipants.employeeId })
232	    .from(channelParticipants)
233	    .where(eq(channelParticipants.channelId, channelId));
234	  const participantIdList = participantIds.map((p) => p.id);
235	
236	  // Priority ordering: gap_priority enum is ('low','medium','high','urgent').
237	  // We need urgent first → use CASE.
238	  const candidates = await db
239	    .select({
240	      id: gaps.id,
241	      priority: gaps.priority,
242	      questionToAsk: gaps.questionToAsk,
243	      whyItMatters: gaps.whyItMatters,
244	      targetEmployeeId: gaps.targetEmployeeId,
245	      createdAt: gaps.createdAt,
246	    })
247	    .from(gaps)
248	    .where(eq(gaps.status, 'open'))
249	    .orderBy(
250	      sql`CASE ${gaps.priority}
251	            WHEN 'urgent' THEN 1
252	            WHEN 'high'   THEN 2
253	            WHEN 'medium' THEN 3
254	            WHEN 'low'    THEN 4
255	            ELSE 5
256	          END`,
257	      desc(gaps.createdAt),
258	    )
259	    .limit(50);
260	
261	  // Filter: targetEmployeeId is null (channel-agnostic) OR a participant.
262	  const eligible = candidates.find((g) => {
263	    if (g.targetEmployeeId === null) return true;
264	    return participantIdList.includes(g.targetEmployeeId);
265	  });
266	
267	  const topRelevantOpenGap: RelevantOpenGap | null = eligible
268	    ? {
269	        id: eligible.id,
270	        priority: eligible.priority as RelevantOpenGap['priority'],
271	        questionToAsk: eligible.questionToAsk,
272	        whyItMatters: eligible.whyItMatters,
273	      }
274	    : null;
275	
276	  // Check whether any employee is currently typing in this channel.
277	  // The client upserts a typing_indicators row on keystrokes with expires_at = now+5s;
278	  // stale rows (disconnected clients) are excluded by the expires_at filter.
279	  const typingRow = await db
280	    .select({ channelId: typingIndicators.channelId })
281	    .from(typingIndicators)
282	    .where(
283	      and(
284	        eq(typingIndicators.channelId, channelId),
285	        sql`${typingIndicators.expiresAt} > NOW()`,
286	      ),
287	    )
288	    .limit(1);
289	  const isAnyoneTyping = typingRow.length > 0;
290	
291	  return {
292	    channelId,
293	    isGroupChat,
294	    secondsSinceLastUserMessage,
295	    minutesSinceLastOracleInterjection,
296	    interjectionsInLastHour,
297	    topRelevantOpenGap,
298	    recentMessageExcerpts,
299	    isAnyoneTyping,
300	  };
301	}
302	
303	// ─── Drafting via OracleAIClient.runText (interview route) ──────────────────
304	async function draftLullQuestion(
305	  db: ReturnType<typeof getDirectDb>,
306	  client: OracleAIClient,
307	  route: OracleModelRoute,
308	  gap: RelevantOpenGap,
309	  recentMessageExcerpts: string[],
310	): Promise<{ text: string; modelRunId: string | null }> {
311	  const recentContext = recentMessageExcerpts.length === 0
312	    ? '(no recent messages)'
313	    : recentMessageExcerpts.map((m, i) => `[${i + 1}] ${m}`).join('\n');
314	
315	  const userMessage = `Open question to ask: ${gap.questionToAsk}
316	Why it matters: ${gap.whyItMatters}
317	
318	Recent messages in this channel (oldest first, for tone reference — do not directly quote):
319	${recentContext}`;
320	
321	  const blocks = [
322	    makeBlock({
323	      id: 'sys',
324	      label: 'Lull-interjection system prompt',
325	      kind: 'stable_system',
326	      content: LULL_DRAFT_SYSTEM,
327	      cacheEligible: true,
328	      reasonIncluded: 'spec 5.1 Rule 2 — lull interjection drafting',
329	    }),
330	    makeBlock({
331	      id: 'gap-input',
332	      label: 'Gap + recent context',
333	      kind: 'dynamic_input',
334	      content: userMessage,
335	      cacheEligible: false,
336	      reasonIncluded: 'current gap and recent messages',
337	    }),
338	  ];
339	
340	  const callStartedAt = Date.now();
341	  let modelRunId: string | null = null;
342	  try {
343	    const result = await client.runText({
344	      taskType: 'gap_generation',
345	      routeId: route.routeId,
346	      promptVersion: LULL_INTERJECTION_PROMPT_VERSION,
347	      blocks,
348	      providerOptions: { temperature: 0.4 },
349	    });
350	    const latencyMs = Date.now() - callStartedAt;
351	    const actualRouteId = result.routeId ?? route.routeId;
352	    const actualProvider = result.provider ?? route.provider;
353	    const actualModelId = result.modelId ?? route.modelId;
354	
355	    const [contextPack] = await db
356	      .insert(oracleContextPacks)
357	      .values({
358	        taskType: 'gap_generation',
359	        routeId: route.routeId,
360	        promptVersion: LULL_INTERJECTION_PROMPT_VERSION,
361	        stablePrefixHash: hashString(LULL_DRAFT_SYSTEM),
362	        dynamicInputHash: hashString(userMessage),
363	        blocksJson: blocks.map((b) => ({
364	          id: b.id,
365	          kind: b.kind,
366	          hash: b.hash,
367	          tokenEstimate: b.tokenEstimate,
368	        })),
369	        includedGapIds: [gap.id],
370	      })
371	      .returning({ id: oracleContextPacks.id });
372	    if (!contextPack) throw new Error('failed to insert oracle_context_packs row');
373	
374	    const [modelRun] = await db
375	      .insert(modelRuns)
376	      .values({
377	        taskType: 'lull-interjection',
378	        model: actualModelId,
379	        provider: actualProvider,
380	        promptVersion: LULL_INTERJECTION_PROMPT_VERSION,
381	        inputHash: hashString(LULL_DRAFT_SYSTEM),
382	        inputTokens: result.usage.inputTokens ?? null,
383	        outputTokens: result.usage.outputTokens ?? null,
384	        latencyMs,
385	        success: true,
386	      })
387	      .returning({ id: modelRuns.id });
388	    if (!modelRun) throw new Error('failed to insert model_runs row');
389	    modelRunId = modelRun.id;
390	
391	    await db.insert(modelRunUsageDetails).values({
392	      modelRunId: modelRun.id,
393	      contextPackId: contextPack.id,
394	      routeId: actualRouteId,
395	      inputTokens: result.usage.inputTokens ?? null,
396	      outputTokens: result.usage.outputTokens ?? null,
397	      cachedInputTokens: result.usage.cachedInputTokens ?? null,
398	      cacheWriteTokens: result.usage.cacheWriteTokens ?? null,
399	      reasoningTokens: result.usage.reasoningTokens ?? null,
400	      providerRequestId: result.usage.providerRequestId ?? null,
401	      rawUsageJson: (result.usage.rawUsageJson ?? null) as Record<string, unknown> | null,
402	      fellBackFromRouteId: result.fellBackFromRouteId ?? null,
403	      fallbackReason: result.fallbackReason ?? null,
404	    });
405	
406	    await db
407	      .update(oracleContextPacks)
408	      .set({ modelRunId: modelRun.id })
409	      .where(eq(oracleContextPacks.id, contextPack.id));
410	
411	    const text = (result.text ?? '').trim();
412	    if (text.length === 0) {
413	      throw new Error('drafting returned empty text');
414	    }
415	    return { text, modelRunId };
416	  } catch (err) {
417	    const latencyMs = Date.now() - callStartedAt;
418	    const message = err instanceof Error ? err.message : String(err);
419	    try {
420	      const [modelRun] = await db
421	        .insert(modelRuns)
422	        .values({
423	          taskType: 'lull-interjection',
424	          model: route.modelId,
425	          provider: route.provider,
426	          promptVersion: LULL_INTERJECTION_PROMPT_VERSION,
427	          latencyMs,
428	          success: false,
429	          error: message,
430	        })
431	        .returning({ id: modelRuns.id });
432	      modelRunId = modelRun?.id ?? null;
433	    } catch {
434	      /* swallow */
435	    }
436	    throw err;
437	  }
438	}
439	
440	// ─── Per-channel processing ─────────────────────────────────────────────────
441	interface ChannelOutcome {
442	  channelId: string;
443	  decision: 'ask' | 'skip';
444	  reasonCode?: string;
445	  interjectionMessageId?: string;
446	  gapId?: string;
447	  errorMessage?: string;
448	}
449	
450	async function processChannel(
451	  db: ReturnType<typeof getDirectDb>,
452	  client: OracleAIClient,
453	  route: OracleModelRoute,
454	  channel: { id: string; isGroupChat: boolean },
455	  settings: LullSettings,
456	  now: Date,
457	): Promise<ChannelOutcome> {
458	  const ctx = await loadChannelContext(db, channel.id, channel.isGroupChat, now);
459	
460	  // No user messages ever → nothing to interrupt; treat as long lull but skip
461	  // because the channel hasn't started a conversation yet.
462	  if (ctx.secondsSinceLastUserMessage === null) {
463	    return {
464	      channelId: channel.id,
465	      decision: 'skip',
466	      reasonCode: 'no_user_messages_yet',
467	    };
468	  }
469	
470	  const decisionInput: LullInterjectionInput = {
471	    secondsSinceLastUserMessage: ctx.secondsSinceLastUserMessage,
472	    lullWindowSeconds: settings.lullWindowSeconds,
473	    isAnyoneTyping: ctx.isAnyoneTyping,
474	    minutesSinceLastOracleInterjection: ctx.minutesSinceLastOracleInterjection,
475	    oracleCooldownMinutes: settings.oracleCooldownMinutes,
476	    interjectionsInLastHour: ctx.interjectionsInLastHour,
477	    maxOracleInterjectionsPerHour: settings.maxOracleInterjectionsPerHour,
478	    enableGroupChatLullQuestions: settings.enableGroupChatLullQuestions,
479	    channelKind: channel.isGroupChat ? 'group' : 'dm',
480	    topRelevantOpenGap: ctx.topRelevantOpenGap,
481	  };
482	
483	  const decision = decideLullInterjection(decisionInput);
484	
485	  if (decision.decision === 'skip') {
486	    return {
487	      channelId: channel.id,
488	      decision: 'skip',
489	      reasonCode: decision.reasonCode,
490	    };
491	  }
492	
493	  // decision === 'ask' — draft + post.
494	  try {
495	    if (!ctx.topRelevantOpenGap) {
496	      // The decider already enforces this, but TS doesn't know.
497	      return { channelId: channel.id, decision: 'skip', reasonCode: 'no_relevant_gap' };
498	    }
499	    const drafted = await draftLullQuestion(db, client, route, ctx.topRelevantOpenGap, ctx.recentMessageExcerpts);
500	
501	    // Insert the assistant message (no employeeId — Oracle messages are
502	    // employeeId=null per the schema; role='assistant').
503	    const [interjectionMessage] = await db
504	      .insert(messages)
505	      .values({
506	        channelId: channel.id,
507	        employeeId: null,
508	        role: 'assistant',
509	        content: drafted.text,
510	        // extractionStatus stays 'pending' default per schema; the extraction
511	        // worker queries role='user' so it'll naturally skip Oracle messages.
512	        metadataJson: {
513	          source: 'lull-interjection',
514	          gapId: ctx.topRelevantOpenGap.id,
515	          modelRunId: drafted.modelRunId,
516	          decisionReason: decision.reason,
517	        },
518	      })
519	      .returning({ id: messages.id });
520	    if (!interjectionMessage) throw new Error('failed to insert assistant message');
521	
522	    // Record the intervention.
523	    await db.insert(oracleInterventions).values({
524	      channelId: channel.id,
525	      triggerType: 'lull_gap',
526	      relatedGapId: ctx.topRelevantOpenGap.id,
527	      interjectionMessageId: interjectionMessage.id,
528	      confidence: null,
529	      impactScore: null,
530	      wasLiveInterjection: true,
531	      reason: decision.reason,
532	    });
533	
534	    // Mark the gap as asked.
535	    await db
536	      .update(gaps)
537	      .set({
538	        status: 'asked',
539	        askedInMessageId: interjectionMessage.id,
540	        updatedAt: new Date(),
541	      })
542	      .where(eq(gaps.id, ctx.topRelevantOpenGap.id));
543	
544	    return {
545	      channelId: channel.id,
546	      decision: 'ask',
547	      interjectionMessageId: interjectionMessage.id,
548	      gapId: ctx.topRelevantOpenGap.id,
549	    };
550	  } catch (err) {
551	    const errorMessage = err instanceof Error ? err.message : String(err);
552	    console.error(`[lull-interjection] channel ${channel.id} drafting/posting failed:`, errorMessage);
553	    return {
554	      channelId: channel.id,
555	      decision: 'skip',
556	      reasonCode: 'drafting_failed',
557	      errorMessage,
558	    };
559	  }
560	}
561	
562	// ─── Top-level scheduled task ───────────────────────────────────────────────
563	export const lullInterjectionTask = schedules.task({
564	  id: 'lull-interjection',
565	  // Every minute. The cooldown + rate-cap gates inside decideLullInterjection
566	  // handle the actual interjection frequency; this just makes sure we check
567	  // often enough that a 60s lull window can fire promptly.
568	  cron: '* * * * *',
569	  maxDuration: 60 * 2,
570	  run: async (_payload, { ctx }) => {
571	    const db = getDirectDb();
572	    const client = buildOracleClient();
573	    const startedAt = new Date();
574	
575	    const [jobRun] = await db
576	      .insert(jobRuns)
577	      .values({
578	        triggerRunId: ctx.run.id,
579	        jobType: 'lull-interjection',
580	        status: 'running',
581	        startedAt,
582	      })
583	      .returning({ id: jobRuns.id });
584	    if (!jobRun) throw new Error('[lull-interjection] failed to insert job_runs row');
585	
586	    const totals = {
587	      channelsConsidered: 0,
588	      interjectionsAsked: 0,
589	      skipsByReason: {} as Record<string, number>,
590	      errors: 0,
591	    };
592	
593	    try {
594	      const lullSettings = await loadLullSettings(db);
595	      const route = await resolveInterviewRoute(db);
596	
597	      const activeChannels = await db
598	        .select({ id: channels.id, isGroupChat: channels.isGroupChat })
599	        .from(channels)
600	        .where(eq(channels.status, 'active'));
601	
602	      for (const channel of activeChannels) {
603	        totals.channelsConsidered += 1;
604	        try {
605	          const outcome = await processChannel(db, client, route, channel, lullSettings, new Date());
606	          if (outcome.decision === 'ask') {
607	            totals.interjectionsAsked += 1;
608	          } else {
609	            const code = outcome.reasonCode ?? 'unknown';
610	            totals.skipsByReason[code] = (totals.skipsByReason[code] ?? 0) + 1;
611	            if (outcome.errorMessage) totals.errors += 1;
612	          }
613	        } catch (chanErr) {
614	          totals.errors += 1;
615	          console.error(`[lull-interjection] channel ${channel.id} failed:`, chanErr);
616	        }
617	      }
618	
619	      await db
620	        .update(jobRuns)
621	        .set({ status: 'complete', finishedAt: new Date(), outputJson: totals })
622	        .where(eq(jobRuns.id, jobRun.id));
623	
624	      return { ok: true, ...totals };
625	    } catch (fatalErr) {
626	      await db
627	        .update(jobRuns)
628	        .set({
629	          status: 'failed',
630	          finishedAt: new Date(),
631	          error: fatalErr instanceof Error ? fatalErr.message : String(fatalErr),
632	        })
633	        .where(eq(jobRuns.id, jobRun.id));
634	      throw fatalErr;
635	    }
636	  },
637	});
