373	async function buildLiveRetrievalContext(args: {
374	  db: ReturnType<typeof getDirectDb>;
375	  currentUtterance: string;
376	  recentContext: string;
377	}): Promise<LiveRetrievalContext | null> {
378	  const retrievalQuery = [
379	    stripOracleAddress(args.currentUtterance),
380	    args.recentContext ? `Recent meeting context:\n${args.recentContext}` : '',
381	  ].filter(Boolean).join('\n\n');
382	  if (!retrievalQuery) return null;
383	
384	  try {
385	    const plan = buildRetrievalPlanFromQuery(retrievalQuery, { topK: LIVE_RETRIEVAL_TOP_K });
386	    const claims = await searchWithRetrievalPlan(args.db, plan);
387	    const evidenceByClaim = await loadEvidenceForClaims(args.db, claims.map((c) => c.id));
388	    const sectionRows = claims.length > 0
389	      ? await args.db
390	          .select({ sectionId: sectionClaims.sectionId })
391	          .from(sectionClaims)
392	          .where(inArray(sectionClaims.claimId, claims.map((c) => c.id)))
393	          .limit(2)
394	      : [];
395	    const sectionIds = Array.from(new Set(sectionRows.map((r) => r.sectionId))).slice(0, 2);
396	    const brainSnippets = await getBrainSectionSnippets(args.db, sectionIds);
397	
398	    const enrichedClaims: LiveRetrievedClaimContext[] = claims.map((claim) => {
399	      const evidence = evidenceByClaim.get(claim.id);
400	      return {
401	        ...claim,
402	        evidenceId: evidence?.evidenceId ?? null,
403	        evidenceQuote: evidence?.exactQuote ?? null,
404	        sourceMessageId: evidence?.sourceMessageId ?? null,
405	        sourceDocumentChunkId: evidence?.sourceDocumentChunkId ?? null,
406	        sourceExternalRecordId: evidence?.sourceExternalRecordId ?? null,
407	      };
408	    });
409	
410	    const claimsText = enrichedClaims.length > 0
411	      ? enrichedClaims.map((claim, i) => {
412	          const quote = claim.evidenceQuote
413	            ? ` Evidence: "${truncateForPrompt(claim.evidenceQuote, 220)}"`
414	            : '';
415	          return `[C${i + 1}] ${truncateForPrompt(claim.summary, 260)} (impact ${claim.impactScore}, confidence ${claim.confidenceScore}).${quote}`;
416	        }).join('\n')
417	      : 'No approved claims matched this live context.';
418	    const brainText = brainSnippets.length > 0
419	      ? brainSnippets.map((section, i) =>
420	          `[B${i + 1}] ${section.title}: ${truncateForPrompt(section.markdown, 420)}`,
421	        ).join('\n')
422	      : 'No linked Brain sections found for retrieved claims.';
423	    const contextText = `Approved claims:\n${claimsText}\n\nLinked Brain sections:\n${brainText}`;
424	
425	    return {
426	      plan,
427	      claims: enrichedClaims,
428	      brainSections: brainSnippets,
429	      contextText,
430	      includedClaimIds: enrichedClaims.map((c) => c.id),
431	      includedEvidenceIds: enrichedClaims.flatMap((c) => c.evidenceId ? [c.evidenceId] : []),
432	      includedBrainSectionIds: brainSnippets.map((s) => s.sectionId),
433	    };
434	  } catch (err) {
435	    const cause = err instanceof Error && err.cause instanceof Error ? ` cause: ${err.cause.message}` : '';
436	    console.warn(
437	      '[teams-live-recall-utterance] retrieval failed; deciding without approved-knowledge context',
438	      `${err instanceof Error ? err.message.slice(0, 300) : String(err)}${cause}`,
439	    );
440	    return null;
441	  }
442	}
