444	async function decideLiveQuestion(args: {
445	  db: ReturnType<typeof getDirectDb>;
446	  client: OracleAIClient;
447	  route: OracleModelRoute;
448	  channelId: string;
449	  currentUtterance: string;
450	  speakerName: string | null;
451	}): Promise<{
452	  decision: LiveQuestionDecision;
453	  modelRunId: string | null;
454	  retrievalContext: LiveRetrievalContext | null;
455	}> {
456	  const recent = await args.db
457	    .select({ id: messages.id, content: messages.content, metadataJson: messages.metadataJson, createdAt: messages.createdAt })
458	    .from(messages)
459	    .where(and(eq(messages.channelId, args.channelId), eq(messages.role, 'user'), isNull(messages.deletedAt)))
460	    .orderBy(desc(messages.createdAt))
461	    .limit(RECENT_UTTERANCE_LIMIT);
462	
463	  const recentContext = recent
464	    .slice()
465	    .reverse()
466	    .map((m, i) => {
467	      const meta = (m.metadataJson ?? {}) as { speaker?: string };
468	      return `[${i + 1}] ${meta.speaker ? `${meta.speaker}: ` : ''}${m.content}`;
469	    })
470	    .join('\n');
471	  const retrievalContext = await buildLiveRetrievalContext({
472	    db: args.db,
473	    currentUtterance: args.currentUtterance,
474	    recentContext,
475	  });
476	  const retrievalContextText = retrievalContext?.contextText ?? 'Approved-knowledge retrieval was unavailable for this utterance.';
477	  const userContent = `Recent finalized meeting utterances (oldest first):
478	${recentContext}
479	
480	Retrieved approved Oracle knowledge:
481	${retrievalContextText}
482	
483	Current utterance to evaluate:
484	${args.speakerName ? `${args.speakerName}: ` : ''}${args.currentUtterance}`;
485	
486	  const blocks = [
487	    makeBlock({
488	      id: 'sys',
489	      label: 'Teams live Oracle decision system',
490	      kind: 'stable_system',
491	      content: LIVE_ORACLE_SYSTEM,
492	      cacheEligible: true,
493	      reasonIncluded: 'live Teams meeting interjection decision',
494	    }),
495	    ...(retrievalContext
496	      ? [
497	          makeBlock({
498	            id: 'retrieved-claims',
499	            label: 'Retrieved approved Oracle knowledge',
500	            kind: 'retrieved_context' as const,
501	            content: retrievalContext.contextText,
502	            cacheEligible: false,
503	            reasonIncluded: 'approved claims and Brain sections retrieved for live Teams decision',
504	          }),
505	        ]
506	      : []),
507	    makeBlock({
508	      id: 'utterances',
509	      label: 'Recent finalized utterances',
510	      kind: 'dynamic_input',
511	      content: userContent,
512	      cacheEligible: false,
513	      reasonIncluded: 'rolling live Teams transcript window',
514	    }),
515	  ];
516	
517	  const [contextPack] = await args.db
518	    .insert(oracleContextPacks)
519	    .values({
520	      taskType: 'interview_chat',
521	      routeId: args.route.routeId,
522	      promptVersion: LIVE_PROMPT_VERSION,
523	      stablePrefixHash: hashString(LIVE_ORACLE_SYSTEM),
524	      retrievedContextHash: retrievalContext ? hashString(retrievalContext.contextText) : null,
525	      dynamicInputHash: hashString(userContent),
526	      blocksJson: blocks.map((b) => ({
527	        id: b.id,
528	        kind: b.kind,
529	        hash: b.hash,
530	        tokenEstimate: b.tokenEstimate,
531	      })),
532	      selectedDomains: retrievalContext
