765	async function resolveExtractionRoute(db: OracleDb): Promise<OracleModelRoute> {
766	  const resolved = await resolveRouteFromSettings(db, 'extraction');
767	  if (resolved) return resolved;
768	  const fb = getOracleRoute(FALLBACK_ROUTE_ID);
769	  if (!fb) {
770	    throw new Error(
771	      `[document-ingestion] default_extraction_route unset/unresolvable and fallback "${FALLBACK_ROUTE_ID}" missing.`,
772	    );
773	  }
774	  console.warn(
775	    `[document-ingestion] default_extraction_route unset/unresolvable; using fallback "${FALLBACK_ROUTE_ID}".`,
776	  );
777	  return fb;
778	}
