780	async function loadActiveTopDomainIds(db: OracleDb): Promise<string[]> {
781	  const { sql } = await import('drizzle-orm');
782	  const rows = await db.execute<{ id: string }>(
783	    sql`SELECT id FROM knowledge_top_domains WHERE is_active = true`,
784	  );
785	  // eslint-disable-next-line @typescript-eslint/no-explicit-any
786	  const list: Array<{ id: string }> = (rows as any).rows ?? (rows as any);
787	  return list.map((r) => r.id);
788	}
789	
790	/**
791	 * Load the entity registry slice used by R5.5 validateTaxonomy. For round 1
792	 * we load all rows (the seed is ~56 rows) — see claim-extraction.ts for the
793	 * scoping plan when the registry grows.
794	 */
795	async function loadEntityRegistry(db: OracleDb): Promise<RegistryEntity[]> {
796	  const rows = await db
797	    .select({
798	      id: entities.id,
799	      entityType: entities.entityType,
800	      canonicalValue: entities.canonicalValue,
801	      aliases: entities.aliases,
802	    })
803	    .from(entities);
804	  return rows.map((r) => ({
805	    id: r.id,
806	    entityType: r.entityType as EntityType,
807	    canonicalValue: r.canonicalValue,
808	    aliases: (r.aliases as string[] | null) ?? null,
809	  }));
810	}
811	
812	function buildContextPackInsert(plan: OraclePromptPlan) {
813	  return {
814	    taskType: plan.taskType,
815	    routeId: plan.routeId,
816	    promptVersion: plan.promptVersion,
