91	// ─────────────────────────────────────────────────────────────────────────
92	// Top-level Trigger.dev task
93	// ─────────────────────────────────────────────────────────────────────────
94	
95	export interface ClaimExtractionRunTotals {
96	  ok: boolean;
97	  batchesProcessed: number;
98	  candidatesStaged: number;
99	  claimsPromoted: number;
100	  duplicatesAppended: number;
101	  rejections: number;
102	  circuitBreakerTrips: number;
103	  messagesProcessed: number;
104	  errors: number;
105	}
106	
107	// Core run body extracted so wet-test runners and future integration tests
108	// can invoke a single pass without going through the Trigger.dev runtime.
109	// `triggerRunId` accepts a real `ctx.run.id` from Trigger.dev OR any unique
110	// string for local invocation (the value is stored on the `job_runs` row).
111	export async function runClaimExtractionOnce(
112	  triggerRunId: string,
113	): Promise<ClaimExtractionRunTotals> {
114	    const db = getDirectDb();
115	    const client = buildOracleClient();
116	    const startedAt = new Date();
117	
118	    const [jobRun] = await db
119	      .insert(jobRuns)
120	      .values({
121	        triggerRunId,
122	        jobType: 'claim-extraction',
123	        status: 'running',
124	        startedAt,
125	        inputJson: { batchSize: BATCH_SIZE },
126	      })
127	      .returning({ id: jobRuns.id });
128	    if (!jobRun) throw new Error('[claim-extraction] failed to insert job_runs row');
129	
130	    const totals = {
131	      batchesProcessed: 0,
132	      candidatesStaged: 0,
133	      claimsPromoted: 0,
134	      duplicatesAppended: 0,
135	      rejections: 0,
136	      circuitBreakerTrips: 0,
137	      messagesProcessed: 0,
138	      errors: 0,
139	    };
140	
141	    try {
142	      // 0. Dispatch-mode gate. If settings.extraction_dispatch_mode === 'batch'
143	      //    the batch-submit worker owns extraction; the sync path bails. The
144	      //    flag is read every run so admins can flip back to sync without
145	      //    redeploying. See DECISIONS.md D14.
146	      const dispatchModeRow = await db
147	        .select({ value: settings.value })
148	        .from(settings)
149	        .where(eq(settings.key, 'extraction_dispatch_mode'))
150	        .limit(1);
151	      const dispatchMode = (dispatchModeRow[0]?.value as string | undefined) ?? 'sync';
152	      if (dispatchMode === 'batch') {
153	        await db
154	          .update(jobRuns)
155	          .set({
156	            status: 'complete',
157	            finishedAt: new Date(),
158	            outputJson: { ...totals, skipped: true, reason: 'extraction_dispatch_mode=batch — handled by claim-extraction-batch-submit' },
159	          })
160	          .where(eq(jobRuns.id, jobRun.id));
161	        return { ok: true, ...totals };
162	      }
163	
164	      // 1. Resolve the curated extraction route.
165	      const route = await resolveExtractionRoute(db);
166	      const activeTopDomainIds = await loadActiveTopDomainIds(db);
167	      const entityRegistry = await loadEntityRegistry(db);
168	
169	      // 2. Pull pending user messages.
170	      const pendingMessages = await db
171	        .select({
172	          id: messages.id,
173	          channelId: messages.channelId,
174	          employeeId: messages.employeeId,
175	          role: messages.role,
176	          content: messages.content,
177	          createdAt: messages.createdAt,
178	          authorName: employees.name,
179	        })
180	        .from(messages)
181	        .leftJoin(employees, eq(employees.id, messages.employeeId))
182	        .where(and(eq(messages.extractionStatus, 'pending'), eq(messages.role, 'user')))
183	        .orderBy(messages.createdAt)
184	        .limit(BATCH_SIZE);
185	
186	      if (pendingMessages.length === 0) {
187	        await db
188	          .update(jobRuns)
189	          .set({ status: 'complete', finishedAt: new Date(), outputJson: totals })
190	          .where(eq(jobRuns.id, jobRun.id));
191	        return { ok: true, ...totals };
192	      }
193	
194	      // 3. Mark all fetched messages as 'processing' (idempotency guard).
195	      const messageIds = pendingMessages.map((m) => m.id);
196	      await db
197	        .update(messages)
198	        .set({ extractionStatus: 'processing' })
199	        .where(inArray(messages.id, messageIds));
200	
201	      // 4. Group by channel → 60-min conversation segments.
202	      const segments = groupIntoSegments(pendingMessages);
203	
204	      // 5. Process each segment as an extraction_batches row.
205	      for (const segment of segments) {
206	        try {
207	          const outcome = await processSegment({
208	            db,
209	            client,
210	            route,
211	            activeTopDomainIds,
212	            entityRegistry,
213	            jobRunId: jobRun.id,
214	            segment,
215	          });
216	          totals.batchesProcessed += 1;
217	          totals.candidatesStaged += outcome.candidatesStaged;
218	          totals.claimsPromoted += outcome.claimsPromoted;
219	          totals.duplicatesAppended += outcome.duplicatesAppended;
220	          totals.rejections += outcome.rejections;
221	          totals.circuitBreakerTrips += outcome.circuitBreakerTripped ? 1 : 0;
222	          totals.messagesProcessed += outcome.messagesProcessed;
223	        } catch (segErr) {
224	          totals.errors += 1;
225	          console.error('[claim-extraction] segment processing failed', segErr);
226	          // The segment-level error path already updates the batch + messages
227	          // to 'failed'; nothing more to do here.
228	        }
229	      }
230	
231	      await db
232	        .update(jobRuns)
233	        .set({ status: 'complete', finishedAt: new Date(), outputJson: totals })
234	        .where(eq(jobRuns.id, jobRun.id));
235	
236	      return { ok: true, ...totals };
237	    } catch (fatalErr) {
238	      await db
239	        .update(jobRuns)
240	        .set({
241	          status: 'failed',
242	          finishedAt: new Date(),
243	          error: fatalErr instanceof Error ? fatalErr.message : String(fatalErr),
244	        })
245	        .where(eq(jobRuns.id, jobRun.id));
246	      throw fatalErr;
247	    }
248	}
