913	export async function resolveExtractionRoute(db: OracleDb): Promise<OracleModelRoute> {
914	  // Reads both default_extraction_route + default_extraction_reasoning_effort.
915	  const resolved = await resolveRouteFromSettings(db, 'extraction');
916	  if (resolved) return resolved;
917	  const fallback = getOracleRoute(FALLBACK_ROUTE_ID);
918	  if (!fallback) {
919	    throw new Error(
920	      `[claim-extraction] default_extraction_route unset/unresolvable and fallback "${FALLBACK_ROUTE_ID}" missing.`,
921	    );
922	  }
923	  console.warn(
924	    `[claim-extraction] default_extraction_route unset/unresolvable; using fallback "${FALLBACK_ROUTE_ID}".`,
925	  );
926	  return fallback;
927	}
