1046	function legacyStanceToCandidateStance(
1047	  role: string | undefined,
1048	): 'stated' | 'confirmed' | 'challenged' | 'refined' | 'exception_introduced' | 'ambiguity_revealed' | null {
1049	  switch (role) {
1050	    case 'claim_stated':
1051	      return 'stated';
1052	    case 'claim_confirmed':
1053	      return 'confirmed';
1054	    case 'claim_challenged':
1055	      return 'challenged';
1056	    case 'claim_refined':
1057	      return 'refined';
1058	    case 'exception_introduced':
1059	      return 'exception_introduced';
1060	    case 'process_ambiguity_revealed':
1061	      return 'ambiguity_revealed';
1062	    default:
1063	      return null;
1064	  }
1065	}
