299	/** merge_top_domains: re-tag all claim_top_domains from source → target, deactivate source. */
300	async function handleMergeTopDomains(
301	  db: ReturnType<typeof getDirectDb>,
302	  payload: ProposalPayload,
303	): Promise<HandlerResult> {
304	  const sourceTopDomainId = payload.sourceTopDomainId as string | undefined;
305	  const targetTopDomainId = payload.targetTopDomainId as string | undefined;
306	
307	  if (!sourceTopDomainId || !targetTopDomainId) {
308	    return { applied: false, reason: 'payload missing sourceTopDomainId or targetTopDomainId' };
309	  }
310	
311	  const targetExists = await db
312	    .select({ id: knowledgeTopDomains.id })
313	    .from(knowledgeTopDomains)
314	    .where(eq(knowledgeTopDomains.id, targetTopDomainId))
315	    .limit(1);
316	  if (!targetExists.length) {
317	    return { applied: false, reason: `target top-domain ${targetTopDomainId} not found` };
318	  }
319	
320	  // Move claim_top_domains rows not already pointing at target.
321	  const alreadyInTarget = await db
322	    .select({ claimId: claimTopDomains.claimId })
323	    .from(claimTopDomains)
324	    .where(eq(claimTopDomains.topDomainId, targetTopDomainId));
325	  const skipIds = alreadyInTarget.map((r) => r.claimId);
326	
327	  const moveWhere =
328	    skipIds.length > 0
329	      ? and(
330	          eq(claimTopDomains.topDomainId, sourceTopDomainId),
331	          notInArray(claimTopDomains.claimId, skipIds),
332	        )
333	      : eq(claimTopDomains.topDomainId, sourceTopDomainId);
334	
335	  const moved = await db
336	    .update(claimTopDomains)
337	    .set({ topDomainId: targetTopDomainId })
338	    .where(moveWhere)
339	    .returning({ claimId: claimTopDomains.claimId });
340	
341	  // Delete remaining source rows (duplicates already in target).
342	  await db
343	    .delete(claimTopDomains)
344	    .where(eq(claimTopDomains.topDomainId, sourceTopDomainId));
345	
346	  // Deactivate source domain.
347	  await db
348	    .update(knowledgeTopDomains)
349	    .set({ isActive: false })
350	    .where(eq(knowledgeTopDomains.id, sourceTopDomainId));
351	
352	  return {
353	    applied: true,
354	    afterState: {
355	      sourceTopDomainId,
356	      targetTopDomainId,
357	      movedCount: moved.length,
358	      sourceStatus: 'deactivated',
359	    },
