366	
367	async function applyProposal(
368	  db: ReturnType<typeof getDirectDb>,
369	  proposal: PendingProposal,
370	  dryRun: boolean,
371	): Promise<{ proposalId: string; changeType: string; applied: boolean; note: string }> {
372	  if (dryRun) {
373	    return {
374	      proposalId: proposal.id,
375	      changeType: `dry_run_${proposal.proposalType}`,
376	      applied: false,
377	      note: 'dry-run — no mutation applied',
378	    };
379	  }
380	
381	  let result: HandlerResult;
382	
383	  switch (proposal.proposalType) {
384	    case 'create_sub_topic':
385	      result = await handleCreateSubTopic(db, proposal.payload);
386	      break;
387	    case 'reassign_claims':
388	      result = await handleReassignClaims(db, proposal.payload);
389	      break;
390	    case 'merge_sub_topics':
391	      result = await handleMergeSubTopics(db, proposal.payload);
392	      break;
393	    case 'retire_sub_topic':
394	      result = await handleRetireSubTopic(db, proposal.payload);
395	      break;
396	    case 'merge_top_domains':
397	      result = await handleMergeTopDomains(db, proposal.payload);
398	      break;
399	    case 'split_top_domain':
400	    case 'split_sub_topic':
401	      result = {
402	        applied: false,
403	        reason: `${proposal.proposalType} requires manual admin intervention — claim-level split cannot be automated safely.`,
404	      };
405	      break;
406	    default:
407	      result = { applied: false, reason: `unknown proposal type: ${proposal.proposalType}` };
408	  }
409	
410	  const changeType = result.applied
411	    ? `reclassification_applied_${proposal.proposalType}`
412	    : `reclassification_skipped_${proposal.proposalType}`;
413	
414	  await db.insert(taxonomyChangeLog).values({
415	    changeType,
416	    beforeState: { proposalId: proposal.id, proposalType: proposal.proposalType },
417	    afterState: result.applied ? result.afterState : { reason: result.reason },
418	    reason: result.applied ? 'Applied by taxonomy-reclassification worker' : result.reason,
419	    proposalId: proposal.id,
420	  });
421	
422	  return {
423	    proposalId: proposal.id,
424	    changeType,
425	    applied: result.applied,
426	    note: result.applied ? 'applied' : result.reason,
427	  };
428	}
