434	export const taxonomyReclassificationTask = task({
435	  id: 'taxonomy-reclassification',
436	  maxDuration: 60 * 5,
437	  run: async (payload: z.infer<typeof ManualTriggerPayload>, { ctx }) => {
438	    const parsed = ManualTriggerPayload.parse(payload);
439	    const db = getDirectDb();
440	
441	    const [jobRun] = await db
442	      .insert(jobRuns)
443	      .values({
444	        triggerRunId: ctx.run.id,
445	        jobType: 'taxonomy-reclassification',
446	        status: 'running',
447	        startedAt: new Date(),
448	        inputJson: { proposalType: parsed.proposalType ?? null, dryRun: parsed.dryRun ?? false },
449	      })
450	      .returning({ id: jobRuns.id });
451	    if (!jobRun) throw new Error('[taxonomy-reclassification] failed to insert job_runs row');
452	
453	    try {
454	      const pending = await findPendingReclassifications(db, parsed.proposalType);
455	
456	      const results = [];
457	      for (const proposal of pending) {
458	        const r = await applyProposal(db, proposal, parsed.dryRun ?? false);
459	        results.push(r);
460	      }
461	
462	      const appliedCount = results.filter((r) => r.applied).length;
463	      const skippedCount = results.length - appliedCount;
464	
465	      const output = {
466	        ok: true as const,
467	        dryRun: parsed.dryRun ?? false,
468	        proposalsFound: pending.length,
469	        proposalsApplied: appliedCount,
470	        proposalsSkipped: skippedCount,
471	        results,
472	      };
473	
474	      await db
475	        .update(jobRuns)
476	        .set({ status: 'complete', finishedAt: new Date(), outputJson: output })
477	        .where(sql`id = ${jobRun.id}`);
478	
479	      return output;
480	    } catch (err) {
481	      await db
482	        .update(jobRuns)
483	        .set({
484	          status: 'failed',
485	          finishedAt: new Date(),
486	          error: err instanceof Error ? err.message : String(err),
487	        })
488	        .where(sql`id = ${jobRun.id}`);
489	      throw err;
490	    }
491	  },
492	});
