/**
 * Choose the document chunk to attach as the evidence pointer for a quote.
 *
 * Searches the full rawText for the quote (raw, then whitespace-normalized as a
 * fallback for minor model reformatting). If found, returns the chunk whose
 * [start,end) window contains the match's start offset. Falls back to chunk[0]
 * only when the quote can't be located in rawText at all (the downstream quote
 * validator then records the failure).
 */
function pickEvidenceChunk(
  rawText: string,
  exactQuote: string,
  chunks: Array<{ id: string; text: string; start: number; end: number }>,
): { id: string; text: string; start: number; end: number } {
  const fallback = chunks[0]!;
  if (!exactQuote) return fallback;

  let matchOffset = rawText.indexOf(exactQuote);
  if (matchOffset < 0) {
    // Tolerate whitespace differences: search a whitespace-collapsed copy and
    // map the collapsed offset back to an approximate rawText offset.
    const collapsedRaw = rawText.replace(/\s+/g, ' ');
    const collapsedQuote = exactQuote.replace(/\s+/g, ' ').trim();
    const collapsedIdx = collapsedQuote ? collapsedRaw.indexOf(collapsedQuote) : -1;
    if (collapsedIdx < 0) return fallback;
    // Walk rawText counting non-collapsed characters until we reach collapsedIdx.
    let consumed = 0;
    for (let i = 0; i < rawText.length; i++) {
      if (consumed >= collapsedIdx) { matchOffset = i; break; }
      // Each run of whitespace collapses to a single space in collapsedRaw.
      if (/\s/.test(rawText[i]!)) {
        if (i === 0 || !/\s/.test(rawText[i - 1]!)) consumed += 1;
      } else {
        consumed += 1;
      }
    }
    if (matchOffset < 0) return fallback;
  }

  const covering = chunks.find((c) => matchOffset >= c.start && matchOffset < c.end);
  return covering ?? fallback;
}

